// ─── CALCULATION HELPERS ──────────────────────────────────────────────────────
function sumHours(data, role) {
  return data.filter((r) => r.role === role).reduce((s, r) => s + r.st + r.ot + r.dt, 0);
}

function sumExpense(data, role) {
  return data.filter((r) => r.role === role).reduce((s, r) => s + r.stPay + r.otPay + r.dtPay, 0);
}

function findTopPerformer(data, role) {
  const byEmployee = {};
  for (const r of data.filter((row) => row.role === role)) {
    if (!byEmployee[r.name]) byEmployee[r.name] = { name: r.name, hours: 0 };
    byEmployee[r.name].hours += r.st + r.ot + r.dt;
  }
  const entries = Object.values(byEmployee);
  if (entries.length === 0) return null;
  entries.sort((a, b) => b.hours - a.hours || a.name.localeCompare(b.name));
  return entries[0];
}

// ─── DATE/NUMBER UTILITIES ────────────────────────────────────────────────────
function excelDateToDate(value) {
  if (!value) return null;
  if (value instanceof Date) return value;
  if (typeof value === "number") {
    // Excel serial date (days since 1900-01-01, with leap year bug) — local time, no UTC shift
    const days = Math.round(value) - 25569;
    const d = new Date(1970, 0, 1);
    d.setDate(d.getDate() + days);
    return isNaN(d.getTime()) ? null : d;
  }
  if (typeof value === "string" && value.trim()) {
    const parts = value.trim().match(/^(\d{1,2})[\/\-](\d{1,2})[\/\-](\d{4})$/);
    if (parts) return new Date(+parts[3], +parts[1] - 1, +parts[2]);
    const d = new Date(value.trim() + "T00:00:00");
    return isNaN(d.getTime()) ? null : d;
  }
  return null;
}

function dateToExcelSerial(date) {
  // Convert JS Date to Excel serial number
  return date.getTime() / 86400000 + 25569;
}

function formatDate(d) {
  const m = String(d.getMonth() + 1).padStart(2, "0");
  const day = String(d.getDate()).padStart(2, "0");
  return `${m}/${day}/${d.getFullYear()}`;
}

function toNum(val) {
  const n = parseFloat(val);
  return isNaN(n) ? 0 : n;
}

// Expand a starting column letter to N consecutive columns
// e.g. expandColumns("A", 5) → ["A","B","C","D","E"]
// e.g. expandColumns("G", 5) → ["G","H","I","J","K"]
function expandColumns(startCol, count) {
  const start = colLetterToIndex(startCol);
  const result = [];
  for (let i = 0; i < count; i++) {
    result.push(indexToColLetter(start + i));
  }
  return result;
}

function colLetterToIndex(col) {
  let n = 0;
  for (const ch of col.toUpperCase()) {
    n = n * 26 + (ch.charCodeAt(0) - 64);
  }
  return n; // 1-based
}

function indexToColLetter(n) {
  let result = "";
  while (n > 0) {
    const rem = (n - 1) % 26;
    result = String.fromCharCode(65 + rem) + result;
    n = Math.floor((n - 1) / 26);
  }
  return result;
}

// ─── APPLY SHEET THEME ────────────────────────────────────────────────────────
export async function applySheetTheme() {
  setLoading(true);
  try {
    await Excel.run(async (context) => {
      // Get active sheet + used range
      const sheet = context.workbook.activeWorksheet;
      const used = sheet.getUsedRangeOrNullObject();
      used.load(["isNullObject", "values", "rowCount", "columnCount", "address"]);
      await context.sync();

      if (used.isNullObject || used.rowCount === 0) return;

      const vals = used.values;
      const R = used.rowCount;
      const C = used.columnCount;

      // Parse top-left cell of used range (handles "Sheet1!A1:Z50" and "'My Sheet'!A1:Z50")
      const addrStr = used.address.includes("!") ? used.address.split("!")[1] : used.address;
      const addrClean = addrStr.replace(/\$/g, "");
      const m = addrClean.match(/^([A-Z]+)(\d+)/i);
      const sc = m ? colLetterToIndex(m[1].toUpperCase()) : 1;
      const sr = m ? parseInt(m[2], 10) : 1;

      const cellAddr = (r, c) => `${indexToColLetter(sc + c)}${sr + r}`;
      const rowAddr = (r) =>
        `${indexToColLetter(sc)}${sr + r}:${indexToColLetter(sc + C - 1)}${sr + r}`;

      const YEAR_RE = /^(201[0-9]|202[0-9]|203[0-5])$/;
      const KEY_RE = /\b(total|grand total|summary|subtotal)\b/i;
      const NOTE_RE = /^\s*(\*{1,2}|†|notes?:|source:)/i;

      // 3. Base: body defaults on entire used range
      const allRange = sheet.getRange(used.address);
      allRange.format.font.color = "#111827";
      allRange.format.font.size = 11;
      for (const edge of [
        "EdgeTop",
        "EdgeBottom",
        "EdgeLeft",
        "EdgeRight",
        "InsideHorizontal",
        "InsideVertical",
      ]) {
        try {
          allRange.format.borders.getItem(edge).style = Excel.BorderLineStyle.thin;
          allRange.format.borders.getItem(edge).color = "#E5E7EB";
        } catch (_) {
          /* single-cell ranges skip inside borders */
        }
      }

      // 4. Row-by-row classification (priority: Title > Note > KeyValue > Header > Subtitle > Body)
      for (let r = 0; r < R; r++) {
        const row = vals[r];
        const nonEmpty = row.filter((v) => v !== null && v !== "");
        if (nonEmpty.length === 0) continue;

        const firstStr = (row[0] ?? "").toString().trim();
        const numCount = nonEmpty.filter((v) => typeof v === "number").length;
        const strCount = nonEmpty.filter((v) => typeof v === "string" && v.trim() !== "").length;
        const emptyCount = row.filter((v) => v === null || v === "").length;
        const range = sheet.getRange(rowAddr(r));

        // ── Title: first row of used range ──
        if (r === 0) {
          range.format.font.bold = true;
          range.format.font.size = 26;
          range.format.font.color = "#1F2937";
          continue;
        }

        // ── Note / Footnote ──
        if (NOTE_RE.test(firstStr)) {
          range.format.font.color = "#6B7280";
          range.format.font.size = 9;
          range.format.font.italic = true;
          continue;
        }

        // ── Key Value row (Total / Grand Total / Summary / Subtotal) ──
        if (KEY_RE.test(firstStr) && numCount > 0) {
          range.format.font.bold = true;
          range.format.font.color = "#16A34A";
          range.format.fill.color = "#F0FDF4";
          range.format.horizontalAlignment = Excel.HorizontalAlignment.right;
          // Keep label left-aligned
          sheet.getRange(cellAddr(r, 0)).format.horizontalAlignment =
            Excel.HorizontalAlignment.left;
          continue;
        }

        // ── Header row: 2+ non-empty cells all text, no numbers ──
        if (strCount >= 2 && numCount === 0 && strCount === nonEmpty.length) {
          range.format.font.bold = true;
          range.format.font.color = "#FFFFFF";
          range.format.fill.color = "#374151";
          range.format.horizontalAlignment = Excel.HorizontalAlignment.center;
          continue;
        }

        // ── Subtitle / Section heading: text in first col, ≥50% of row empty, no numbers ──
        if (
          typeof row[0] === "string" &&
          firstStr !== "" &&
          numCount === 0 &&
          emptyCount >= Math.ceil(C * 0.5)
        ) {
          const cell = sheet.getRange(cellAddr(r, 0));
          cell.format.font.bold = true;
          cell.format.font.size = 13;
          cell.format.font.color = "#8B5E00";
          cell.format.borders.getItem("EdgeTop").style = Excel.BorderLineStyle.thin;
          cell.format.borders.getItem("EdgeTop").color = "#E5E7EB";
          continue;
        }

        // ── Body: wrap if long text ──
        const hasLong = row.some((v) => typeof v === "string" && v.length > 60);
        if (hasLong) {
          range.format.wrapText = true;
        }
      }

      // 5. Year cells — scan every cell in used range
      for (let r = 0; r < R; r++) {
        for (let c = 0; c < C; c++) {
          const v = vals[r][c];
          const isYear =
            (typeof v === "string" && YEAR_RE.test(v.trim())) ||
            (typeof v === "number" && Number.isInteger(v) && v >= 2019 && v <= 2035);
          if (!isYear) continue;
          const cell = sheet.getRange(cellAddr(r, c));
          cell.format.font.bold = true;
          cell.format.font.color = "#0EA5E9";
          cell.format.borders.getItem("EdgeBottom").style = Excel.BorderLineStyle.thin;
          cell.format.borders.getItem("EdgeBottom").color = "#E5E7EB";
        }
      }

      // ── Autofit all rows ───────────────────────────────────────────────────
      allRange.format.autofitRows();

      await context.sync();
    });
    showToast("Sheet theme applied.");
  } catch (err) {
    console.error("applySheetTheme error:", err);
    showMessage(`Theme error: ${err.message}`);
  } finally {
    setLoading(false);
  }
}
